import{_ as a,o as e,c as r,S as l}from"./chunks/framework.C6RQlTYc.js";const m=JSON.parse('{"title":"大语言模型（LLM）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_6-llm.md","filePath":"直击概念/17ai/s_ai_6-llm.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_6-llm.md"};function o(d,t,n,s,h,g){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="大语言模型-llm" tabindex="-1">大语言模型（LLM） <a class="header-anchor" href="#大语言模型-llm" aria-label="Permalink to &quot;大语言模型（LLM）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>大语言模型（Large Language Model，LLM）是一种基于 Transformer 架构的大规模神经网络，通过在海量文本数据上训练，获得了<strong>理解和生成自然语言</strong>的能力。LLM 的核心能力是<strong>预测下一个 token</strong>——给定前文，预测最可能出现的后续内容。</p><p>LLM 的标志性突破包括：</p><ul><li>2018：GPT-1 和 BERT 开创预训练范式</li><li>2020：GPT-3（175B 参数），证明 Scaling Law 有效</li><li>2022：ChatGPT（GPT-3.5），RLHF 对齐让模型可用</li><li>2023：GPT-4、Claude 2、Llama 2、Gemini</li><li>2024：GPT-4o、Claude 3.5、Llama 3、DeepSeek V3</li></ul><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><h3 id="涌现能力-emergent-abilities" tabindex="-1">涌现能力（Emergent Abilities） <a class="header-anchor" href="#涌现能力-emergent-abilities" aria-label="Permalink to &quot;涌现能力（Emergent Abilities）&quot;">​</a></h3><p>当模型参数规模超过某个阈值时，会出现一些<strong>小模型不具备</strong>的能力，如：</p><ul><li><strong>上下文学习（In-Context Learning）</strong>：仅通过 prompt 中的示例学习新任务，无需微调</li><li><strong>思维链推理（Chain-of-Thought）</strong>：通过逐步推导解决复杂问题</li><li><strong>指令遵循（Instruction Following）</strong>：理解和执行自然语言指令</li></ul><h3 id="scaling-law" tabindex="-1">Scaling Law <a class="header-anchor" href="#scaling-law" aria-label="Permalink to &quot;Scaling Law&quot;">​</a></h3><p>模型性能随<strong>参数数量、训练数据量、计算量</strong>的增长而<strong>可预测地提升</strong>。这是 LLM 不断&quot;变大&quot;的理论基础。</p><h2 id="主流-llm-对比" tabindex="-1">主流 LLM 对比 <a class="header-anchor" href="#主流-llm-对比" aria-label="Permalink to &quot;主流 LLM 对比&quot;">​</a></h2><table><thead><tr><th>模型</th><th>开发方</th><th>特点</th><th>开源</th></tr></thead><tbody><tr><td>GPT-4o</td><td>OpenAI</td><td>多模态、全能型</td><td>否</td></tr><tr><td>Claude 3.5</td><td>Anthropic</td><td>长上下文、安全性强</td><td>否</td></tr><tr><td>Gemini</td><td>Google</td><td>多模态、Google 生态</td><td>否</td></tr><tr><td>Llama 3</td><td>Meta</td><td>开源最强之一</td><td>是</td></tr><tr><td>DeepSeek V3</td><td>DeepSeek</td><td>高性价比、MoE 架构</td><td>是</td></tr><tr><td>Qwen 2.5</td><td>阿里</td><td>中文能力强</td><td>是</td></tr><tr><td>Mistral</td><td>Mistral AI</td><td>轻量高效</td><td>部分</td></tr><tr><td>DeepSeek R1</td><td>DeepSeek</td><td>推理能力强（CoT 特化）</td><td>是</td></tr></tbody></table><h2 id="llm-的工作方式" tabindex="-1">LLM 的工作方式 <a class="header-anchor" href="#llm-的工作方式" aria-label="Permalink to &quot;LLM 的工作方式&quot;">​</a></h2><ol><li><strong>输入</strong>：用户输入 prompt 文本</li><li><strong>分词</strong>：将文本切分为 token 序列</li><li><strong>编码</strong>：将 token 序列通过 Transformer 网络处理</li><li><strong>预测</strong>：在最后一层产生每个可能 token 的概率分布</li><li><strong>采样</strong>：根据概率采样生成下一个 token</li><li><strong>循环</strong>：将生成的 token 追加到输入，重复 4-5 步，直到遇到结束标记</li></ol><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>LLM &quot;大&quot;在哪些方面？为什么大更有效？</li><li>你用过哪些 LLM？通过什么方式集成到前端？</li><li>LLM 的局限性有哪些（幻觉、时效性、算力成本等）？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2001.08361" target="_blank" rel="noreferrer">Scaling Laws for Neural Language Models</a></li><li><a href="https://arxiv.org/abs/2303.08774" target="_blank" rel="noreferrer">GPT-4 Technical Report</a></li><li><a href="https://github.com/Hannibal046/Awesome-LLM" target="_blank" rel="noreferrer">Awesome-LLM</a></li></ul>',19)])])}const u=a(i,[["render",o]]);export{m as __pageData,u as default};
